        if 'chi' in fname.lower():
            title = fname.replace('.txt', '').lower().strip()
            if title in cites:
                total += cites[title]
                chi_papers += 1

    result = {'total_2020_citations': total, 'chi_papers_cited': chi_papers}
else:
    result = {'error': 'Variables not found'}

print('__RESULT__:')
print(json.dumps(result))"}

